module RefModule(CLK, RST, Gray);
input CLK, RST;
output [1:0] Gray;
reg [1:0] Gray;
reg [1:0] obf_binary_counter;

always @(posedge CLK or posedge RST) begin
    if (RST) begin
        obf_binary_counter <= 0;
        Gray <= 0;
    end else begin
        obf_binary_counter <= obf_binary_counter + 1;
        Gray <= (obf_binary_counter >> 1) ^ obf_binary_counter;
    end
end

endmodule
